1	const bcrypt = require('bcrypt');
2	const crypto = require('crypto');
3	const { v4: uuidv4 } = require('uuid');
4	const db = require('../database/connection');
5	const { logAudit } = require('./auditService');
6	
7	const BCRYPT_COST = 12;
8	const MAX_FAILED_ATTEMPTS = 5;
9	const LOCKOUT_WINDOW_MS = 10 * 60 * 1000;
10	const LOCKOUT_DURATION_MS = 15 * 60 * 1000;
11	const MAX_LOCKOUTS_24H = 3;
12	const SESSION_HARD_EXPIRY_DAYS = 30;
13	
14	async function checkLockout(username) {
15	  const activeLockout = await db('lockouts')
16	    .where('username', username)
17	    .whereNull('unlocked_at')
18	    .orderBy('locked_at', 'desc')
19	    .first();
20	
21	  if (!activeLockout) return { locked: false };
22	
23	  if (activeLockout.requires_admin_reset) {
24	    return { locked: true, requiresAdminReset: true, message: 'Account locked. Contact administrator.' };
25	  }
26	
27	  const lockExpiry = new Date(activeLockout.locked_at).getTime() + LOCKOUT_DURATION_MS;
28	  if (Date.now() < lockExpiry) {
29	    const remainingSec = Math.ceil((lockExpiry - Date.now()) / 1000);
30	    return { locked: true, remainingSec, message: `Account locked. Try again in ${remainingSec} seconds.` };
31	  }
32	
33	  await db('lockouts').where('id', activeLockout.id).update({ unlocked_at: new Date(), unlock_reason: 'auto_expired' });
34	  return { locked: false };
35	}
