37	async function recordFailedAttempt(username, ip, deviceFingerprint, reason) {
38	  await db('login_attempts').insert({
39	    username, ip_address: ip, device_fingerprint: deviceFingerprint,
40	    success: false, failure_reason: reason
41	  });
42	
43	  const windowStart = new Date(Date.now() - LOCKOUT_WINDOW_MS);
44	  const recentFailures = await db('login_attempts')
45	    .where('username', username)
46	    .where('success', false)
47	    .where('attempted_at', '>=', windowStart)
48	    .count('id as count')
49	    .first();
50	
51	  if (recentFailures.count >= MAX_FAILED_ATTEMPTS) {
52	    // Check if there's already an active lockout -- don't create duplicates
53	    const activeLockout = await db('lockouts')
54	      .where('username', username)
55	      .whereNull('unlocked_at')
56	      .first();
57	    if (activeLockout) {
58	      // Already locked -- don't create a duplicate
59	      return;
60	    }
61	
62	    // Count DISTINCT lockout windows in last 24 hours (only resolved/expired ones plus the new one)
63	    const dayStart = new Date(Date.now() - 24 * 60 * 60 * 1000);
64	    const recentLockouts = await db('lockouts')
65	      .where('username', username)
66	      .where('locked_at', '>=', dayStart)
67	      .count('id as count')
68	      .first();
69	
70	    const lockoutCount = (recentLockouts.count || 0) + 1;
71	    const requiresAdminReset = lockoutCount >= MAX_LOCKOUTS_24H;
72	
73	    await db('lockouts').insert({
74	      username,
75	      lockout_count_24h: lockoutCount,
76	      requires_admin_reset: requiresAdminReset
77	    });
78	
79	    await logAudit(null, username, 'lockout', 'user', null, { lockoutCount, requiresAdminReset, ip });
80	  }
81	}
