83	async function login({ username, password, deviceFingerprint, ipAddress }) {
84	  const lockStatus = await checkLockout(username);
85	  if (lockStatus.locked) {
86	    return { success: false, error: lockStatus.message, locked: true };
87	  }
88	
89	  const user = await db('users').where('username', username).where('is_active', true).first();
90	  if (!user) {
91	    await recordFailedAttempt(username, ipAddress, deviceFingerprint, 'user_not_found');
92	    return { success: false, error: 'Invalid username or password.' };
93	  }
94	
95	  const valid = await bcrypt.compare(password, user.password_hash);
96	  if (!valid) {
97	    await recordFailedAttempt(username, ipAddress, deviceFingerprint, 'invalid_password');
98	    return { success: false, error: 'Invalid username or password.' };
99	  }
100	
101	  // Device fingerprint is mandatory — fail closed if missing
102	  if (!deviceFingerprint || typeof deviceFingerprint !== 'string' || deviceFingerprint.trim().length === 0) {
103	    return { success: false, error: 'Device fingerprint is required for login.' };
104	  }
105	
106	  const trusted = await db('trusted_devices')
107	    .where('user_id', user.id)
108	    .where('device_fingerprint', deviceFingerprint)
109	    .first();
110	
111	  if (!trusted) {
112	    // Check for unused recovery codes
113	    const unusedCodes = await db('recovery_codes')
114	      .where('user_id', user.id)
115	      .where('is_used', false)
116	      .first();
117	
118	    if (unusedCodes) {
119	      // Has unused codes — require device verification
120	      const pendingToken = uuidv4();
121	      const pendingTokenHash = crypto.createHash('sha256').update(pendingToken).digest('hex');
122	      const pendingExpiry = new Date(Date.now() + 10 * 60 * 1000);
123	      await db('sessions').insert({
124	        id: pendingTokenHash,
125	        user_id: user.id,
126	        device_fingerprint: 'PENDING_VERIFICATION',
127	        state: 'pending_verification',
128	        ip_address: ipAddress,
129	        expires_at: pendingExpiry
130	      });
131	      return {
132	        success: true,
133	        requireDeviceVerification: true,
134	        sessionToken: pendingToken
135	      };
136	    }
137	
138	    // No unused codes — check if codes were ever generated
139	    const anyCodes = await db('recovery_codes').where('user_id', user.id).first();
140	    if (anyCodes) {
141	      // All codes exhausted — block until admin regenerates
142	      await logAudit(user.id, username, 'login_blocked_codes_exhausted', 'user', user.id, { ip: ipAddress, deviceFingerprint });
143	      return { success: false, error: 'All recovery codes exhausted. Contact administrator to generate new codes.' };
144	    }
145	
146	    // No codes ever generated — enrollment required
147	    // Platform Ops can generate codes for this user via POST /api/auth/recovery-codes or admin endpoint
148	    await logAudit(user.id, username, 'login_blocked_enrollment_required', 'user', user.id, { ip: ipAddress, deviceFingerprint });
149	    return {
150	      success: false,
151	      error: 'Device enrollment required. Contact administrator to generate recovery codes for your account.',
152	      enrollmentRequired: true
153	    };
154	  }
155	
156	  // Session limits — only count active sessions, not pending_verification
157	  const activeCount = await db('sessions')
158	    .where('user_id', user.id)
159	    .where('state', 'active')
160	    .where('expires_at', '>', new Date())
161	    .count('id as count')
162	    .first();
163	
164	  let maxSessions = user.max_sessions || 2;
165	  const exception = await db('session_exceptions')
166	    .where('user_id', user.id)
167	    .where(function() { this.whereNull('expires_at').orWhere('expires_at', '>', new Date()); })
168	    .orderBy('created_at', 'desc')
169	    .first();
170	  if (exception) maxSessions = exception.max_sessions;
171	
172	  if (activeCount.count >= maxSessions) {
173	    const oldest = await db('sessions')
174	      .where('user_id', user.id)
175	      .where('state', 'active')
176	      .where('expires_at', '>', new Date())
177	      .orderBy('last_active_at', 'asc')
178	      .orderBy('created_at', 'asc')
179	      .orderBy('id', 'asc')
180	      .first();
181	    if (oldest) await db('sessions').where('id', oldest.id).del();
182	  }
183	
184	  // Create session
185	  const token = uuidv4();
186	  const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
187	  const expiresAt = new Date(Date.now() + SESSION_HARD_EXPIRY_DAYS * 24 * 60 * 60 * 1000);
188	
189	  await db('sessions').insert({
190	    id: tokenHash, user_id: user.id, device_fingerprint: deviceFingerprint || null,
191	    state: 'active', ip_address: ipAddress, expires_at: expiresAt
192	  });
193	
194	  await db('login_attempts').insert({
195	    username, ip_address: ipAddress, device_fingerprint: deviceFingerprint, success: true
196	  });
197	
198	  await logAudit(user.id, username, 'login', 'session', null, { ip: ipAddress, deviceFingerprint });
199	
200	  return {
201	    success: true,
202	    token,
203	    user: { id: user.id, username: user.username, display_name: user.display_name, role: user.role, phone_last4: user.phone_last4 }
204	  };
205	}
