207	async function verifyDevice(userId, code, deviceFingerprint) {
208	  const codes = await db('recovery_codes').where('user_id', userId).where('is_used', false);
209	
210	  for (const stored of codes) {
211	    const match = await bcrypt.compare(code, stored.code_hash);
212	    if (match) {
213	      await db('recovery_codes').where('id', stored.id).update({ is_used: true, used_at: new Date() });
214	
215	      const user = await db('users').where('id', userId).first();
216	
217	      // Require fingerprint
218	      if (!deviceFingerprint || typeof deviceFingerprint !== 'string' || deviceFingerprint.trim().length === 0) {
219	        return { success: false, error: 'Device fingerprint is required for verification.' };
220	      }
221	
222	      // Trust the device
223	      await db('trusted_devices').insert({ user_id: userId, device_fingerprint: deviceFingerprint }).catch(() => {});
224	
225	      // Enforce session cap — only count active sessions, not pending_verification
226	      const activeCount = await db('sessions')
227	        .where('user_id', userId)
228	        .where('state', 'active')
229	        .where('expires_at', '>', new Date())
230	        .count('id as count')
231	        .first();
232	
233	      let maxSessions = user.max_sessions || 2;
234	      const exception = await db('session_exceptions')
235	        .where('user_id', userId)
236	        .where(function() { this.whereNull('expires_at').orWhere('expires_at', '>', new Date()); })
237	        .orderBy('created_at', 'desc')
238	        .first();
239	      if (exception) maxSessions = exception.max_sessions;
240	
241	      if (activeCount.count >= maxSessions) {
242	        const oldest = await db('sessions')
243	          .where('user_id', userId)
244	          .where('state', 'active')
245	          .where('expires_at', '>', new Date())
246	          .orderBy('last_active_at', 'asc')
247	          .orderBy('created_at', 'asc')
248	          .orderBy('id', 'asc')
249	          .first();
250	        if (oldest) await db('sessions').where('id', oldest.id).del();
251	      }
252	
253	      const token = uuidv4();
254	      const tokenHash = crypto.createHash('sha256').update(token).digest('hex');
255	      const expiresAt = new Date(Date.now() + SESSION_HARD_EXPIRY_DAYS * 24 * 60 * 60 * 1000);
256	      await db('sessions').insert({ id: tokenHash, user_id: userId, device_fingerprint: deviceFingerprint, state: 'active', expires_at: expiresAt });
257	
258	      await logAudit(userId, user.username, 'device_verified', 'trusted_device', null, { deviceFingerprint });
259	
260	      return {
261	        success: true,
262	        token,
263	        user: { id: user.id, username: user.username, display_name: user.display_name, role: user.role, phone_last4: user.phone_last4 }
264	      };
265	    }
266	  }
267	
268	  return { success: false, error: 'Invalid recovery code.' };
269	}
270	
271	async function generateRecoveryCodes(userId) {
272	  await db('recovery_codes').where('user_id', userId).del();
273	
274	  const codes = [];
275	  for (let i = 0; i < 10; i++) {
276	    const code = crypto.randomBytes(4).toString('hex').toUpperCase();
277	    const hash = await bcrypt.hash(code, BCRYPT_COST);
278	    codes.push({ plaintext: code, hash });
279	  }
280	
281	  await db('recovery_codes').insert(codes.map(c => ({ user_id: userId, code_hash: c.hash })));
282	  return codes.map(c => c.plaintext);
283	}
284	
285	async function unlockUser(username, adminId, adminUsername) {
286	  await db('lockouts')
287	    .where('username', username)
288	    .whereNull('unlocked_at')
289	    .update({ unlocked_at: new Date(), unlock_reason: 'admin_reset', unlocked_by: adminId });
290	
291	  await logAudit(adminId, adminUsername, 'user_unlocked', 'user', null, { unlockedUser: username });
292	}
293	
294	module.exports = { login, verifyDevice, generateRecoveryCodes, unlockUser, checkLockout };
