2	const db = require('../database/connection');
3	const { authenticate, optionalAuth, requireRole } = require('../middleware/auth');
4	const { createError } = require('../middleware/errorHandler');
5	const { logAudit } = require('../services/auditService');
6	const { normalize, findMatchingStations } = require('../utils/fuzzyMatch');
7	
8	const router = new Router({ prefix: '/api/stations' });
9	
10	/**
11	 * GET /api/stations
12	 * List stations. Supports fuzzy search via ?q= parameter.
13	 * Optionally authenticated — works for anonymous and logged-in users alike.
14	 */
15	router.get('/', optionalAuth(), async (ctx) => {
16	  const { page = 1, pageSize = 25, q } = ctx.query;
17	  const limit = Math.min(parseInt(pageSize, 10) || 25, 100);
18	  const offset = (Math.max(parseInt(page, 10) || 1, 1) - 1) * limit;
19	
20	  if (q && q.trim().length > 0) {
21	    // --- Fuzzy search mode ---
22	    const allStations = await db('stations')
23	      .where('is_active', true)
24	      .select('id', 'code', 'name', 'name_normalized', 'region', 'is_active', 'created_at');
25	
26	    // Load aliases for fuzzy matching
27	    const aliases = await db('station_aliases').select('station_id', 'alias', 'alias_normalized');
28	    const aliasMap = {};
29	    for (const a of aliases) {
30	      if (!aliasMap[a.station_id]) aliasMap[a.station_id] = [];
31	      aliasMap[a.station_id].push(a);
32	    }
33	
34	    const stationsWithAliases = allStations.map((s) => ({
35	      ...s,
36	      aliases: aliasMap[s.id] || []
37	    }));
38	
39	    const matched = findMatchingStations(q, stationsWithAliases);
40	
41	    // Host scope: filter to assigned stations only
42	    let filteredMatched = matched;
43	    if (ctx.state.user && ctx.state.user.role === 'host') {
44	      const assignedIds = ctx.state.user.assignedStationIds || [];
45	      filteredMatched = matched.filter(s => assignedIds.includes(s.id));
46	    }
47	
48	    const total = filteredMatched.length;
49	    const paged = filteredMatched.slice(offset, offset + limit);
50	
51	    ctx.body = {
52	      success: true,
53	      data: {
54	        results: paged.map((s) => ({
55	          id: s.id,
56	          code: s.code,
57	          name: s.name,
58	          region: s.region,
59	          isActive: s.is_active,
60	          createdAt: s.created_at
61	        })),
62	        total,
63	        page: parseInt(page, 10) || 1,
64	        pageSize: limit
65	      }
66	    };
67	    return;
68	  }
69	
70	  // --- Standard paginated list ---
71	  // For host users, filter to only their assigned stations
72	  let stationQuery = db('stations');
73	  let stationCountQuery = db('stations');
74	
75	  if (ctx.state.user && ctx.state.user.role === 'host') {
76	    const assignedIds = await db('user_station_scopes')
77	      .where('user_id', ctx.state.user.id)
78	      .select('station_id');
79	    const ids = assignedIds.map(r => r.station_id);
80	    stationQuery = stationQuery.whereIn('id', ids);
81	    stationCountQuery = stationCountQuery.whereIn('id', ids);
82	  }
83	
84	  const totalResult = await stationCountQuery.count('id as count').first();
85	  const total = totalResult ? totalResult.count : 0;
86	
87	  const stations = await stationQuery
88	    .orderBy('name', 'asc')
89	    .limit(limit)
90	    .offset(offset)
91	    .select('id', 'code', 'name', 'region', 'is_active', 'created_at');
92	
93	  ctx.body = {
94	    success: true,
95	    data: {
96	      results: stations.map((s) => ({
97	        id: s.id,
98	        code: s.code,
99	        name: s.name,
100	        region: s.region,
101	        isActive: s.is_active,
102	        createdAt: s.created_at
103	      })),
104	      total,
105	      page: parseInt(page, 10) || 1,
106	      pageSize: limit
107	    }
108	  };
109	});
