111	/**
112	 * GET /api/stations/:id
113	 * Get a single station with its aliases.
114	 */
115	router.get('/:id', optionalAuth(), async (ctx) => {
116	  const { id } = ctx.params;
117	
118	  const station = await db('stations').where('id', id).first();
