149	/**
150	 * POST /api/stations
151	 * Create a new station. Platform Ops only.
152	 * Required fields: code, name.
153	 */
154	router.post('/', authenticate(), requireRole('platform_ops'), async (ctx) => {
155	  const { code, name, region } = ctx.request.body || {};
156	
157	  if (!code || typeof code !== 'string' || code.trim().length === 0) {
158	    throw createError(400, 'VALIDATION_ERROR', 'code is required.');
159	  }
160	  if (!name || typeof name !== 'string' || name.trim().length === 0) {
161	    throw createError(400, 'VALIDATION_ERROR', 'name is required.');
162	  }
163	
164	  // Check uniqueness of code
165	  const existingCode = await db('stations').where('code', code).first();
166	  if (existingCode) {
167	    throw createError(409, 'CONFLICT', 'Station code already exists.');
168	  }
169	
170	  const nameNormalized = normalize(name);
171	  const now = new Date();
172	
173	  const [stationId] = await db('stations').insert({
174	    code,
175	    name,
176	    name_normalized: nameNormalized,
177	    region: region || null,
178	    is_active: true,
179	    created_at: now
180	  });
181	
182	  await logAudit(
183	    ctx.state.user.id,
184	    ctx.state.user.username,
185	    'station.create',
186	    'stations',
187	    stationId,
188	    { code, name, region: region || null },
189	    ctx.ip
190	  );
191	
192	  ctx.status = 201;
193	  ctx.body = {
194	    success: true,
195	    data: {
196	      id: stationId,
197	      code,
198	      name,
199	      region: region || null,
200	      isActive: true,
201	      createdAt: now
202	    }
203	  };
204	});
