206	/**
207	 * PATCH /api/stations/:id
208	 * Update a station. Platform Ops only.
209	 */
210	router.patch('/:id', authenticate(), requireRole('platform_ops'), async (ctx) => {
211	  const { id } = ctx.params;
212	  const { name, code, region, is_active } = ctx.request.body || {};
213	
214	  const station = await db('stations').where('id', id).first();
215	  if (!station) {
216	    throw createError(404, 'NOT_FOUND', 'Station not found.');
217	  }
218	
219	  const updates = {};
220	  const changedFields = {};
221	
222	  if (name !== undefined) {
223	    if (typeof name !== 'string' || name.trim().length === 0) {
224	      throw createError(400, 'VALIDATION_ERROR', 'name must be a non-empty string.');
225	    }
226	    updates.name = name;
227	    updates.name_normalized = normalize(name);
228	    changedFields.name = name;
229	  }
230	
231	  if (code !== undefined) {
232	    if (typeof code !== 'string' || code.trim().length === 0) {
233	      throw createError(400, 'VALIDATION_ERROR', 'code must be a non-empty string.');
234	    }
235	    // Check uniqueness if code is changing
236	    if (code !== station.code) {
237	      const existingCode = await db('stations').where('code', code).whereNot('id', id).first();
238	      if (existingCode) {
239	        throw createError(409, 'CONFLICT', 'Station code already exists.');
240	      }
241	    }
242	    updates.code = code;
243	    changedFields.code = code;
244	  }
245	
246	  if (region !== undefined) {
247	    updates.region = region;
248	    changedFields.region = region;
249	  }
250	
251	  if (is_active !== undefined) {
252	    updates.is_active = !!is_active;
253	    changedFields.is_active = !!is_active;
254	  }
255	
256	  if (Object.keys(updates).length === 0) {
257	    throw createError(400, 'VALIDATION_ERROR', 'No valid fields to update.');
258	  }
259	
260	  await db('stations').where('id', id).update(updates);
261	
262	  await logAudit(
263	    ctx.state.user.id,
264	    ctx.state.user.username,
265	    'station.update',
266	    'stations',
267	    id,
268	    changedFields,
269	    ctx.ip
270	  );
271	
272	  const updated = await db('stations').where('id', id).first();
273	
274	  ctx.body = {
275	    success: true,
276	    data: {
277	      id: updated.id,
278	      code: updated.code,
279	      name: updated.name,
280	      region: updated.region,
281	      isActive: updated.is_active,
282	      createdAt: updated.created_at
283	    }
284	  };
285	});
286	
