 * Device Fingerprinting — Offline-Safe Approximation
 *
 * SECURITY BOUNDARY:
 * This fingerprint is NOT a cryptographically binding machine identity.
 * True hardware-level device identity is not possible from a web browser
 * without native APIs (WebAuthn platform authenticators, TPM, etc.).
 *
 * What this provides:
 * - A persistent random UUID in localStorage as the primary device identifier.
 * - Browser/OS/screen signals as additional entropy for device differentiation.
 * - Sufficient uniqueness for the risky-device challenge flow (new device → recovery code).
 *
 * Known limitations:
 * - The localStorage UUID can be cleared by the user or lost if browser data is wiped.
 * - The same physical machine generates different fingerprints across different browsers.
 * - The fingerprint is not tamper-proof; a user can forge it.
 * - Incognito/private browsing creates a new fingerprint each session.
 *
 * These limitations are acceptable for a LAN-only offline application where the
 * device challenge flow is a defense-in-depth layer, not the sole authentication factor.
 * The primary authentication remains username + password + recovery code.
 */

const STORAGE_KEY = 'railops_device_id';

function getOrCreateDeviceId() {
  try {
    let id = localStorage.getItem(STORAGE_KEY);
    if (!id) {
      id = crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2) + Date.now().toString(36);
      localStorage.setItem(STORAGE_KEY, id);
    }
    return id;
  } catch {
    // localStorage unavailable (e.g., storage quota, privacy mode) — fall back to ephemeral ID
    return crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2) + Date.now().toString(36);
  }
}

export async function generateDeviceFingerprint() {
  const parts = [
    navigator.userAgent || '',
    navigator.platform || '',
    navigator.language || '',
    `${screen.width}x${screen.height}x${screen.colorDepth || ''}`,
    Intl.DateTimeFormat().resolvedOptions().timeZone || '',
    navigator.hardwareConcurrency || '',
    getOrCreateDeviceId()
  ];

  const raw = parts.join('|');

  // Use SHA-256 for a consistent, fixed-length, non-reversible fingerprint
  if (crypto.subtle) {
    try {
      const encoded = new TextEncoder().encode(raw);
      const hashBuffer = await crypto.subtle.digest('SHA-256', encoded);
      const hashArray = Array.from(new Uint8Array(hashBuffer));
      return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    } catch {
      // Fallback if subtle crypto fails (e.g., insecure context without TLS)
    }
  }

  // Fallback: base64 encoding truncated to 64 chars
  return btoa(raw).replace(/[+/=]/g, '').slice(0, 64);
}
