 * Session cap denial unit tests.
 *
 * Tests that the session cap logic DENIES new sessions (instead of evicting)
 * when the limit is reached, unless a session_exception grants a higher cap.
 */

jest.mock('../backend/src/database/connection', () => {
  const mockDb = jest.fn();
  mockDb.raw = jest.fn();
  return mockDb;
});

jest.mock('../backend/src/services/auditService', () => ({
  logAudit: jest.fn()
}));

const db = require('../backend/src/database/connection');
const bcrypt = require('bcrypt');
const { login, verifyDevice } = require('../backend/src/services/authService');

// Helpers
function mockChain(methods) {
  let chain = {};
  for (const [method, value] of Object.entries(methods)) {
    if (typeof value === 'function') {
      chain[method] = value;
    } else {
      chain[method] = jest.fn().mockReturnValue(
        typeof value === 'object' && value !== null && !Array.isArray(value)
          ? mockChain(value)
          : value
      );
    }
  }
  return chain;
}

describe('Session cap denial (login)', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  test('login returns sessionCapExceeded when active sessions >= maxSessions', async () => {
    const passwordHash = await bcrypt.hash('testpass', 4);

    const mockUser = {
      id: 10, username: 'testuser', password_hash: passwordHash,
      display_name: 'Test', role: 'host', is_active: true,
      max_sessions: 2, phone_last4: null
    };

    // Track which table + method is being called
    let callMap = {};
    db.mockImplementation((table) => {
      if (!callMap[table]) callMap[table] = 0;
      callMap[table]++;

      if (table === 'lockouts') {
        return {
          where: jest.fn().mockReturnValue({
            whereNull: jest.fn().mockReturnValue({
              orderBy: jest.fn().mockReturnValue({
                first: jest.fn().mockResolvedValue(null) // no lockout
              })
            })
          })
        };
      }

      if (table === 'users') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              first: jest.fn().mockResolvedValue(mockUser)
            })
          })
        };
      }

      if (table === 'trusted_devices') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              first: jest.fn().mockResolvedValue({ id: 1 }) // device is trusted
            })
          })
        };
      }

      if (table === 'sessions') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              where: jest.fn().mockReturnValue({
                count: jest.fn().mockReturnValue({
                  first: jest.fn().mockResolvedValue({ count: 2 }) // at cap
                })
              })
            })
          })
        };
      }

      if (table === 'session_exceptions') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              orderBy: jest.fn().mockReturnValue({
                first: jest.fn().mockResolvedValue(null) // no exception
              })
            })
          })
        };
      }

      // Default fallback
      return {
        where: jest.fn().mockReturnValue({
          first: jest.fn().mockResolvedValue(null),
          insert: jest.fn().mockResolvedValue([1])
        }),
        insert: jest.fn().mockResolvedValue([1])
      };
    });

    const result = await login({
      username: 'testuser',
      password: 'testpass',
      deviceFingerprint: 'test-fp-123',
      ipAddress: '127.0.0.1'
    });

    expect(result.success).toBe(false);
    expect(result.sessionCapExceeded).toBe(true);
    expect(result.error).toContain('Session limit reached');
    expect(result.error).toContain('2');
  });

  test('login succeeds with session_exception raising cap', async () => {
    const passwordHash = await bcrypt.hash('testpass', 4);

    const mockUser = {
      id: 10, username: 'testuser', password_hash: passwordHash,
      display_name: 'Test', role: 'host', is_active: true,
      max_sessions: 2, phone_last4: null
    };

    db.mockImplementation((table) => {
      if (table === 'lockouts') {
        return {
          where: jest.fn().mockReturnValue({
            whereNull: jest.fn().mockReturnValue({
              orderBy: jest.fn().mockReturnValue({
                first: jest.fn().mockResolvedValue(null)
              })
            })
          })
        };
      }

      if (table === 'users') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              first: jest.fn().mockResolvedValue(mockUser)
            })
          })
        };
      }

      if (table === 'trusted_devices') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              first: jest.fn().mockResolvedValue({ id: 1 })
            })
          })
        };
      }

      if (table === 'sessions') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              where: jest.fn().mockReturnValue({
                count: jest.fn().mockReturnValue({
                  first: jest.fn().mockResolvedValue({ count: 2 }) // 2 active
                })
              })
            })
          }),
          insert: jest.fn().mockResolvedValue([1])
        };
      }

      if (table === 'session_exceptions') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn((fn) => {
              // Simulate the where callback for nullable expires_at
              return {
                orderBy: jest.fn().mockReturnValue({
                  first: jest.fn().mockResolvedValue({ max_sessions: 5 }) // exception: 5 sessions
                })
              };
            })
          })
        };
      }

      if (table === 'login_attempts') {
        return { insert: jest.fn().mockResolvedValue([1]) };
      }

      return {
        where: jest.fn().mockReturnValue({
          first: jest.fn().mockResolvedValue(null)
        }),
        insert: jest.fn().mockResolvedValue([1])
      };
    });

    const result = await login({
      username: 'testuser',
      password: 'testpass',
      deviceFingerprint: 'test-fp-123',
      ipAddress: '127.0.0.1'
    });

    // With exception max_sessions=5, and only 2 active: should succeed
    expect(result.success).toBe(true);
    expect(result.token).toBeTruthy();
    expect(result.sessionCapExceeded).toBeUndefined();
  });
});
