              orderBy: jest.fn().mockReturnValue({
                first: jest.fn().mockResolvedValue(null)
              })
            })
          })
        };
      }

      if (table === 'users') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              first: jest.fn().mockResolvedValue(mockUser)
            })
          })
        };
      }

      if (table === 'trusted_devices') {
        return {
          where: jest.fn().mockReturnValue({
            where: jest.fn().mockReturnValue({
              first: jest.fn().mockResolvedValue({ id: 1, device_fingerprint: 'test-fp' })
            })
          })
        };
      }

      if (table === 'sessions') {
        sessionCallCount++;
        // First call: count active sessions
        if (sessionCallCount === 1) {
          return {
            where: jest.fn().mockReturnValue({
              where: jest.fn().mockReturnValue({
                where: jest.fn().mockReturnValue({
                  count: jest.fn().mockReturnValue({
                    first: jest.fn().mockResolvedValue({ count: activeSessionCount })
                  })
                })
              })
            })
          };
        }
        // Second call: insert new session
        return { insert: jest.fn().mockResolvedValue([1]) };
      }

      if (table === 'session_exceptions') {
        return {
