 * Session cap denial unit tests.
 *
 * Tests that the session cap logic DENIES new sessions (instead of evicting)
 * when the limit is reached, unless a session_exception grants a higher cap.
 */

jest.mock('../backend/src/database/connection', () => {
  const mockDb = jest.fn();
  mockDb.raw = jest.fn();
  return mockDb;
});

jest.mock('../backend/src/services/auditService', () => ({
  logAudit: jest.fn()
}));

const db = require('../backend/src/database/connection');

// Utility: create a deeply chainable mock that returns `finalValue` at any terminal
function chainable(finalValue) {
  const handler = {
    get(target, prop) {
      if (prop === 'then' || prop === 'catch') return undefined; // not thenable
      return (...args) => {
        // If any arg is a function (like knex .where(function() {...})), call it with a dummy
        for (const arg of args) {
          if (typeof arg === 'function') {
            try { arg({ whereNull: () => {}, orWhere: () => {} }); } catch {}
          }
        }
        return new Proxy(target, handler);
      };
    },
    apply() {
      return Promise.resolve(finalValue);
    }
  };

  // Return a callable proxy so it works as both fn() and .prop()
  const fn = function() { return Promise.resolve(finalValue); };
  fn.then = (resolve) => Promise.resolve(finalValue).then(resolve);
  fn.catch = () => Promise.resolve(finalValue);

  return new Proxy(fn, {
    get(target, prop) {
      if (prop === 'then') return (resolve) => Promise.resolve(finalValue).then(resolve);
      if (prop === 'catch') return () => Promise.resolve(finalValue);
      // Return a function that returns another chainable
      return (...args) => {
        for (const arg of args) {
          if (typeof arg === 'function') {
            try { arg({ whereNull: () => chainable(null), orWhere: () => chainable(null) }); } catch {}
          }
        }
        return chainable(finalValue);
      };
    },
    apply() {
      return Promise.resolve(finalValue);
    }
  });
}

describe('Session cap denial (login path)', () => {
  let login;

  beforeAll(() => {
    login = require('../backend/src/services/authService').login;
  });

  beforeEach(() => {
    jest.clearAllMocks();
  });

  function setupLoginMocks({ activeSessionCount, maxSessions, exceptionMaxSessions }) {
    const mockUser = {
      id: 10, username: 'testuser', password_hash: '$2b$12$hash',
      display_name: 'Test', role: 'host', is_active: true,
      max_sessions: maxSessions || 2, phone_last4: null
    };

    let sessionQueryCount = 0;

    db.mockImplementation((table) => {
      if (table === 'lockouts') {
        return chainable(null); // no lockout
      }

      if (table === 'users') {
        return chainable(mockUser);
      }

      if (table === 'trusted_devices') {
        return chainable({ id: 1, device_fingerprint: 'test-fp' });
      }

      if (table === 'sessions') {
        sessionQueryCount++;
