1	/**
2	 * Device Fingerprinting — Offline-Safe Approximation
3	 *
4	 * SECURITY BOUNDARY:
5	 * This fingerprint is NOT a cryptographically binding machine identity.
6	 * True hardware-level device identity is not possible from a web browser
7	 * without native APIs (WebAuthn platform authenticators, TPM, etc.).
8	 *
9	 * What this provides:
10	 * - A persistent random UUID in localStorage as the primary device identifier.
11	 * - Browser/OS/screen signals as additional entropy for device differentiation.
12	 * - Sufficient uniqueness for the risky-device challenge flow (new device → recovery code).
13	 *
14	 * Known limitations:
15	 * - The localStorage UUID can be cleared by the user or lost if browser data is wiped.
16	 * - The same physical machine generates different fingerprints across different browsers.
17	 * - The fingerprint is not tamper-proof; a user can forge it.
18	 * - Incognito/private browsing creates a new fingerprint each session.
19	 *
20	 * These limitations are acceptable for a LAN-only offline application where the
21	 * device challenge flow is a defense-in-depth layer, not the sole authentication factor.
22	 * The primary authentication remains username + password + recovery code.
23	 */
24	
25	const STORAGE_KEY = 'railops_device_id';
26	
27	function getOrCreateDeviceId() {
28	  try {
29	    let id = localStorage.getItem(STORAGE_KEY);
30	    if (!id) {
31	      id = crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2) + Date.now().toString(36);
32	      localStorage.setItem(STORAGE_KEY, id);
33	    }
34	    return id;
35	  } catch {
36	    // localStorage unavailable (e.g., storage quota, privacy mode) — fall back to ephemeral ID
37	    return crypto.randomUUID ? crypto.randomUUID() : Math.random().toString(36).slice(2) + Date.now().toString(36);
38	  }
39	}
40	
41	/**
42	 * Attempt to read the WebGL renderer string, which varies by GPU/driver
43	 * and provides a hardware-correlated signal that is harder to spoof than
44	 * User-Agent alone. Returns empty string if WebGL is unavailable.
45	 */
46	function getWebGLRenderer() {
47	  try {
48	    const canvas = document.createElement('canvas');
49	    const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
50	    if (!gl) return '';
51	    const dbgInfo = gl.getExtension('WEBGL_debug_renderer_info');
52	    if (!dbgInfo) return gl.getParameter(gl.RENDERER) || '';
53	    return gl.getParameter(dbgInfo.UNMASKED_RENDERER_WEBGL) || '';
54	  } catch {
55	    return '';
56	  }
57	}
58	
59	export async function generateDeviceFingerprint() {
60	  const parts = [
61	    navigator.userAgent || '',
62	    navigator.platform || '',
63	    navigator.language || '',
64	    `${screen.width}x${screen.height}x${screen.colorDepth || ''}`,
65	    Intl.DateTimeFormat().resolvedOptions().timeZone || '',
66	    navigator.hardwareConcurrency || '',
67	    getWebGLRenderer(),
68	    getOrCreateDeviceId()
69	  ];
70	
71	  const raw = parts.join('|');
72	
73	  // Use SHA-256 for a consistent, fixed-length, non-reversible fingerprint
74	  if (crypto.subtle) {
75	    try {
76	      const encoded = new TextEncoder().encode(raw);
77	      const hashBuffer = await crypto.subtle.digest('SHA-256', encoded);
78	      const hashArray = Array.from(new Uint8Array(hashBuffer));
79	      return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
80	    } catch {
81	      // Fallback if subtle crypto fails (e.g., insecure context without TLS)
82	    }
83	  }
84	
85	  // Fallback: base64 encoding truncated to 64 chars
86	  return btoa(raw).replace(/[+/=]/g, '').slice(0, 64);
87	}
