19	    // Completeness: schedules with active version must have stops
20	    const activeSchedules = await db('schedules').whereNotNull('active_version_id');
21	    let completeCount = 0;
22	    for (const s of activeSchedules) {
23	      const stopCount = await db('schedule_stops').where('version_id', s.active_version_id).count('id as c').first();
24	      if (parseInt(stopCount.c) > 0) completeCount++;
25	      else {
