27	          .where({ entity_type: 'schedule', entity_id: s.id, check_type: 'completeness' })
28	          .whereIn('status', ['open', 'in_progress'])
29	          .first();
30	        if (!existing) {
31	          await db('data_quality_issues').insert({
32	            entity_type: 'schedule', entity_id: s.id, check_type: 'completeness',
33	            severity: 'high', description: `Schedule ${s.route_name || s.id} has no stops`, status: 'open',
34	            owner: 'platform_ops',
35	            due_date: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]
36	          }).catch(() => {});
37	        }
38	      }
39	    }
40	    checks.push({ name: 'schedule_completeness', total: activeSchedules.length, passed: completeCount, failed: activeSchedules.length - completeCount });
41	
42	    // Uniqueness: duplicate SKUs
43	    const dupSkus = await db('inventory_items').select('sku').groupBy('sku').having(db.raw('COUNT(*) > 1'));
44	    checks.push({ name: 'sku_uniqueness', total: 1, passed: dupSkus.length === 0 ? 1 : 0, failed: dupSkus.length > 0 ? 1 : 0 });
45	
46	    // Freshness: items not updated in 90 days
47	    const staleDate = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000);
48	    const staleItems = await db('inventory_items').where('updated_at', '<', staleDate).count('id as c').first();
49	    checks.push({ name: 'item_freshness', total: 1, passed: parseInt(staleItems.c) === 0 ? 1 : 0, failed: parseInt(staleItems.c) > 0 ? 1 : 0 });
50	
51	    const totalChecks = checks.reduce((s, c) => s + c.total, 0);
52	    const passedChecks = checks.reduce((s, c) => s + c.passed, 0);
53	    const failedChecks = checks.reduce((s, c) => s + c.failed, 0);
54	
55	    await db('data_quality_reports').insert({
56	      report_date: today,
57	      total_checks: totalChecks,
58	      passed_checks: passedChecks,
59	      failed_checks: failedChecks,
60	      issues_found: failedChecks,
61	      report_data: JSON.stringify({ checks, generatedBy: 'scheduler' })
62	    });
63	
64	    console.log(`[DQ_SCHEDULER] Report complete: ${passedChecks}/${totalChecks} passed.`);
65	  } catch (err) {
